import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Znajdowanie wiarygodnych modów","description":"Przewodnik na temat znajdowania modów do Fabric przy użyciu wiarygodnych źródeł.","frontmatter":{"title":"Znajdowanie wiarygodnych modów","description":"Przewodnik na temat znajdowania modów do Fabric przy użyciu wiarygodnych źródeł.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pl_pl/1.21.8/players/finding-mods.md","filePath":"versions/1.21.8/translated/pl_pl/players/finding-mods.md","lastUpdated":1760721669000}`);var a={name:`pl_pl/1.21.8/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Znajdowanie wiarygodnych modów <a class="header-anchor" href="#h1" aria-label="Permalink to “Znajdowanie wiarygodnych modów”">​</a></h1><p>Na wstępie warto wspomnieć, że zaufanie jest subiektywne, dlatego zawsze należy kierować się własnym rozsądkiem podczas pobierania modów. Jest jednak kilka rzeczy, które możesz zrobić, aby znaleźć wiarygodne mody.</p><h2 id="trustworthy-source" tabindex="-1">1. Korzystaj ze źródła, które jest powszechnie uznane za wiarygodne <a class="header-anchor" href="#trustworthy-source" aria-label="Permalink to “1. Korzystaj ze źródła, które jest powszechnie uznane za wiarygodne”">​</a></h2><p>Większość twórców publikuje swoje mody na <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> i CurseForge.</p><p>Strony te sprawdzają, czy mody są tym, za co się podają i czy nie zawierają żadnego złośliwego kodu. Możesz również zgłaszać szkodliwe mody na tych stronach, a one podejmą działania stosunkowo szybko.</p><h2 id="with-others" tabindex="-1">2. Pytaj innych! <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. Pytaj innych!”">​</a></h2><p>Jeśli pobierasz mody ze źródła, które nie jest znane i uznane za wiarygodne, warto spytać innych, czy pobierali już jakieś mody z tej strony i czy mieli z nimi jakiekolwiek problemy.</p><p>W razie wątpliwości zachęcamy do zadawania pytań na <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discordzie Fabric</a> na kanale <code>#player-support</code>.</p><h2 id="avoid-malware" tabindex="-1">3. Unikaj znanych szkodliwych stron! <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. Unikaj znanych szkodliwych stron!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Szkodliwe strony mogą nie być oczywiste dla każdego. Jeśli nie masz pewności, spytaj się innych o opinię lub całkowicie unikaj tej strony i polegaj na wiarygodnych źródłach, takich jak Modrinth i CurseForge.</p></div><p>Jest wiele stron, które twierdzi, że oferuje mody do Minecrafta, choć tak naprawdę zawiera szkodliwe oprogramowanie. Należy ich unikać za wszelką cenę.</p><p>Do sprawdzenia pobranych modów możesz wykorzystać oprogramowanie antywirusowe, takie jak <a href="https://www.microsoft.com/en-us/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> lub strony, takie jak <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a>. Nie należy jednak polegać wyłącznie na tych metodach, ponieważ czasami mogą one być nieprawidłowe.</p><p>Ponownie, jeśli masz jakiekolwiek wątpliwości, możesz spytać się innych o opinię na <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discordzie Fabric</a> na kanale <code>#player-support</code>.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};